// ── GannonHack.Club — Shared JS (nav + dot canvas) ──

// Highlight active nav link based on current page
(function() {
  const path = window.location.pathname;
  document.querySelectorAll('.nav-links a').forEach(a => {
    const href = a.getAttribute('href');
    if (href && path.endsWith(href.replace('../',''))) a.classList.add('active');
    if (href === '../index.html' && (path === '/' || path.endsWith('index.html') && !path.includes('/about') && !path.includes('/blog') && !path.includes('/ctf') && !path.includes('/contact'))) a.classList.add('active');
  });
})();

// ── DOT CANVAS ──
(function() {
  const canvas = document.getElementById('dotCanvas');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  let width, height, dots = [];
  let mouse = { x: -9999, y: -9999 };

  const DOT_COUNT      = 400;
  const LOGO_SIZE      = 50;
  const REPEL_RADIUS   = 130;
  const REPEL_STRENGTH = 5;

  const logo = new Image();
  let logoReady = false;
  logo.onload = () => { logoReady = true; };
  logo.src = 'data:image/png;base64,';

  function resize() {
    width  = canvas.width  = window.innerWidth;
    height = canvas.height = document.body.scrollHeight;
  }

  function createDots() {
    dots = [];
    for (let i = 0; i < DOT_COUNT; i++)
      dots.push({ x: Math.random()*width, y: Math.random()*height, ox:0, oy:0, vx:0, vy:0 });
  }

  function draw() {
    ctx.clearRect(0, 0, width, height);
    const sy = window.scrollY;
    for (let d of dots) {
      const sx = d.x + d.ox, screenY = d.y + d.oy - sy;
      const dx = sx - mouse.x, dy = screenY - mouse.y;
      const dist = Math.sqrt(dx*dx + dy*dy);
      if (dist < REPEL_RADIUS && dist > 0) {
        const f = (REPEL_RADIUS - dist) / REPEL_RADIUS;
        d.vx += (dx/dist)*f*REPEL_STRENGTH;
        d.vy += (dy/dist)*f*REPEL_STRENGTH;
      }
      d.vx += -d.ox * 0.08;  d.vy += -d.oy * 0.08;
      d.vx *= 0.75;           d.vy *= 0.75;
      d.ox += d.vx;           d.oy += d.vy;

      const px = d.x + d.ox, py = d.y + d.oy;
      const od = Math.sqrt((px-mouse.x)**2 + (py-sy-mouse.y)**2);
      ctx.globalAlpha = od < REPEL_RADIUS ? 0.85 : 0.3;
      if (logoReady || (logo.complete && logo.naturalWidth > 0))
        ctx.drawImage(logo, px - LOGO_SIZE/2, py - LOGO_SIZE/2, LOGO_SIZE, LOGO_SIZE);
      else {
        ctx.beginPath(); ctx.arc(px, py, 4, 0, Math.PI*2);
        ctx.fillStyle = '#a08080'; ctx.fill();
      }
      ctx.globalAlpha = 1;
    }
  }

  function loop() { draw(); requestAnimationFrame(loop); }

  window.addEventListener('mousemove', e => { mouse.x = e.clientX; mouse.y = e.clientY; });
  window.addEventListener('mouseleave', () => { mouse.x = -9999; mouse.y = -9999; });
  window.addEventListener('resize', () => { resize(); createDots(); });

  resize(); createDots(); loop();
})();
